# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import sys
from kafka import AdminClient
from kafka.admin import NewTopic, ConfigResource, ConfigResourceType
import argparse

def create_topics(admin_client, topics_config):
    topics_to_create = []
    for topic_config in topics_config:
        topic_name = topic_config['name']
        partitions = topic_config.get('partitions', 1)
        replication_factor = topic_config.get('replication_factor', 1)
        config = topic_config.get('config', {})
        
        topic = NewTopic(
            topic=topic_name,
            num_partitions=partitions,
            replication_factor=replication_factor,
            topic_configs=config
        )
        topics_to_create.append(topic)
    
    try:
        fs = admin_client.create_topics(topics_to_create, validate_only=False)
        for topic, future in fs.items():
            future.result()
        print("Topics created successfully")
    except Exception as e:
        print(f"Error creating topics: {e}")

def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Current topics:")
        for topic in topics:
            print(f"  {topic}")
    except Exception as e:
        print(f"Error listing topics: {e}")

def describe_topic(admin_client, topic_name):
    try:
        topic_configs = admin_client.describe_configs([
            ConfigResource(ConfigResourceType.TOPIC, topic_name)
        ])
        print(f"Configuration for topic '{topic_name}':")
        for resource, config in topic_configs.items():
            for entry in config:
                print(f"  {entry.name}: {entry.value}")
    except Exception as e:
        print(f"Error describing topic: {e}")

def delete_topic(admin_client, topic_name):
    try:
        fs = admin_client.delete_topics([topic_name])
        for topic, future in fs.items():
            future.result()
        print(f"Topic '{topic_name}' deleted successfully")
    except Exception as e:
        print(f"Error deleting topic: {e}")

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers')
    parser.add_argument('--action', choices=['create', 'list', 'describe', 'delete'], required=True, help='Action to perform')
    parser.add_argument('--topic', help='Topic name for describe or delete actions')
    parser.add_argument('--topics-config', help='JSON string with topics configuration')
    
    args = parser.parse_args()
    
    admin_client = AdminClient({'bootstrap.servers': args.bootstrap_servers})
    
    if args.action == 'create':
        if not args.topics_config:
            print("Error: --topics-config is required for create action")
            sys.exit(1)
        
        import json
        topics_config = json.loads(args.topics_config)
        create_topics(admin_client, topics_config)
        
    elif args.action == 'list':
        list_topics(admin_client)
        
    elif args.action == 'describe':
        if not args.topic:
            print("Error: --topic is required for describe action")
            sys.exit(1)
        describe_topic(admin_client, args.topic)
        
    elif args.action == 'delete':
        if not args.topic:
            print("Error: --topic is required for delete action")
            sys.exit(1)
        delete_topic(admin_client, args.topic)

if __name__ == "__main__":
    main()